import java.util.*;

class Solution {
    public int maxTaskAssign(int[] tasks, int[] workers, int pills, int strength) {
        Arrays.sort(tasks);
        Arrays.sort(workers);
        int n = tasks.length, m = workers.length;
        int left = 0, right = Math.min(n, m);
        while (left < right) {
            int mid = (left + right + 1) / 2;
            if (canAssign(tasks, workers, pills, strength, mid)) {
                left = mid;
            } else {
                right = mid - 1;
            }
        }
        return left;
    }

    private boolean canAssign(int[] tasks, int[] workers, int pills, int strength, int k) {
        int n = tasks.length, m = workers.length;
        int[] taskSubset = new int[k];
        for (int i = 0; i < k; i++) {
            taskSubset[i] = tasks[i];
        }
        int[] workerSubset = new int[k];
        for (int i = 0; i < k; i++) {
            workerSubset[i] = workers[m - k + i];
        }
        Arrays.sort(taskSubset);
        Arrays.sort(workerSubset);
        TreeMap<Integer, Integer> map = new TreeMap<>();
        for (int w : workerSubset) {
            map.put(w, map.getOrDefault(w, 0) + 1);
        }
        int pillsLeft = pills;
        for (int t : taskSubset) {
            Integer key = map.ceilingKey(t);
            if (key != null) {
                int cnt = map.get(key);
                if (cnt == 1) {
                    map.remove(key);
                } else {
                    map.put(key, cnt - 1);
                }
            } else {
                key = map.ceilingKey(t - strength);
                if (key != null && pillsLeft > 0) {
                    pillsLeft--;
                    int cnt = map.get(key);
                    if (cnt == 1) {
                        map.remove(key);
                    } else {
                        map.put(key, cnt - 1);
                    }
                } else {
                    return false;
                }
            }
        }
        return true;
    }
}
